/// A singly-linked list node holding a value of type T.
fn LinkedListNode(comptime T: type) type {
    return struct {
        const Self = @This();
        value: T,
        next: ?*Self,
    };
}

fn serialize(comptime T: type, value: T) []const u8 {
    return value.format(); // cryptic error if T has no format()
}

fn serialize(comptime T: type, value: T) []const u8 {
    if (!@hasDecl(T, "format")) {
        @compileError("serialize requires T to have a format() method");
    }
    return value.format();
}

var crc_table: ?[256]u32 = null;
fn getCrcTable() [256]u32 {
    if (crc_table) |t| return t;
    crc_table = computeCrcTable();
    return crc_table.?;
