fn loadData() anyerror!Data {
    const file = try std.fs.cwd().openFile("data.bin", .{});
    return try parseData(file);
}

const LoadError = error{ FileNotFound, AccessDenied, InvalidData };
fn loadData() LoadError!Data {
    const file = std.fs.cwd().openFile("data.bin", .{}) catch |e| switch (e) {
        error.FileNotFound => return error.FileNotFound,
        error.AccessDenied => return error.AccessDenied,
        else => return error.InvalidData,
    };
    return try parseData(file);
}

fn getData() !Data {
    return try loadFromCache(); // caller sees cache errors
}

fn getData() !Data {
    return loadFromCache() catch {
        return try computeData(); // fallback on cache miss
    };
}

